import { useState, useEffect, useCallback } from "react";
import { Button } from "@/components/ui/button";
import { Check, Crown, Loader2, Zap, Store, Star, Sparkles, AlertTriangle, ArrowRight, RotateCcw } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/contexts/AuthContext";
import { useTranslation } from "react-i18next";
import { useCreateMembershipOrder } from "@/hooks/useMembershipOrders";
import { supabase } from "@/integrations/supabase/client";
import { useProfile } from "@/hooks/useProfile";
import { useQueryClient } from "@tanstack/react-query";
import { cn } from "@/lib/utils";
import { Badge } from "@/components/ui/badge";
import { useUserRole } from "@/hooks/useUserRole";
import { useNavigate } from "react-router-dom";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";

type VipTier = "vip1" | "vip2" | "vip3";

interface TierConfig {
  id: VipTier;
  productId: string;
  price: number;
  storeCount: number;
  icon: typeof Crown;
  colorClass: string;
  bgClass: string;
  borderClass: string;
  badgeClass: string;
  role: "merchant" | "supervisor";
}

const TIERS: TierConfig[] = [
  {
    id: "vip1",
    productId: "VIP1",
    price: 9.99,
    storeCount: 1,
    icon: Crown,
    colorClass: "text-amber-600",
    bgClass: "bg-amber-50 dark:bg-amber-950/30",
    borderClass: "border-amber-200 dark:border-amber-800",
    badgeClass: "bg-amber-100 text-amber-800 dark:bg-amber-900 dark:text-amber-200",
    role: "merchant",
  },
  {
    id: "vip2",
    productId: "VIP2",
    price: 17.99,
    storeCount: 2,
    icon: Star,
    colorClass: "text-violet-600",
    bgClass: "bg-violet-50 dark:bg-violet-950/30",
    borderClass: "border-violet-200 dark:border-violet-800",
    badgeClass: "bg-violet-100 text-violet-800 dark:bg-violet-900 dark:text-violet-200",
    role: "supervisor",
  },
  {
    id: "vip3",
    productId: "VIP3",
    price: 24.99,
    storeCount: 3,
    icon: Sparkles,
    colorClass: "text-rose-600",
    bgClass: "bg-rose-50 dark:bg-rose-950/30",
    borderClass: "border-rose-200 dark:border-rose-800",
    badgeClass: "bg-rose-100 text-rose-800 dark:bg-rose-900 dark:text-rose-200",
    role: "supervisor",
  },
];

interface ProductPrice {
  id: string;
  price: string;
  displayPrice: string;
  currencyCode: string;
}

const Membership = () => {
  const { toast } = useToast();
  const { user } = useAuth();
  const { t } = useTranslation();
  const { data: profile } = useProfile();
  const { isMerchant, isSupervisor, role } = useUserRole();
  const navigate = useNavigate();
  const [purchasing, setPurchasing] = useState(false);
  const [restoring, setRestoring] = useState(false);
  const [selectedTier, setSelectedTier] = useState<VipTier>("vip1");
  const [productPrices, setProductPrices] = useState<Record<string, ProductPrice>>({});
  const [showConfirmDialog, setShowConfirmDialog] = useState(false);
  const [pendingTierId, setPendingTierId] = useState<VipTier | null>(null);
  const [showNoStoreDialog, setShowNoStoreDialog] = useState(false);
  const createOrder = useCreateMembershipOrder();
  const queryClient = useQueryClient();

  const isAlreadyMerchant = isMerchant || isSupervisor;

  // Request StoreKit prices from native app
  useEffect(() => {
    (window as any).onReceiveProducts = (products: ProductPrice[]) => {
      const map: Record<string, ProductPrice> = {};
      (products || []).forEach(p => { map[p.id] = p; });
      setProductPrices(map);
    };

    try {
      const webkit = (window as any).webkit;
      if (webkit?.messageHandlers?.VoiceBridge) {
        const ids = TIERS.map(t => t.productId).join(",");
        webkit.messageHandlers.VoiceBridge.postMessage(`getProducts:${ids}`);
      }
    } catch (e) {
      console.log("Not in native app, using default prices");
    }

    return () => { delete (window as any).onReceiveProducts; };
  }, []);

  const currentVip = profile?.vip_level as VipTier | null;
  const vipExpiresAt = profile?.vip_expires_at as string | null;
  const isActive = currentVip && vipExpiresAt && new Date(vipExpiresAt) > new Date();

  const tierLabels: Record<VipTier, string> = {
    vip1: t("membership.vip1", "普通商家"),
    vip2: t("membership.vip2", "高级商家"),
    vip3: t("membership.vip3", "超级商家"),
  };

  const assignRoleAfterPurchase = async (tier: TierConfig) => {
    if (!user) return;
    const targetRole = tier.role;

    // Upsert user_roles
    const { data: existingRole } = await supabase
      .from("user_roles")
      .select("id, role")
      .eq("user_id", user.id)
      .maybeSingle();

    if (existingRole) {
      // Only upgrade, never downgrade
      const roleHierarchy: Record<string, number> = { user: 0, merchant: 1, supervisor: 2, admin: 3 };
      if ((roleHierarchy[targetRole] || 0) > (roleHierarchy[existingRole.role] || 0)) {
        await supabase
          .from("user_roles")
          .update({ role: targetRole })
          .eq("id", existingRole.id);
      }
    } else {
      await supabase
        .from("user_roles")
        .insert({ user_id: user.id, role: targetRole });
    }

    // Update profile
    const expiresAt = new Date();
    expiresAt.setMonth(expiresAt.getMonth() + 1);
    await supabase
      .from("profiles")
      .update({
        vip_level: tier.id,
        vip_expires_at: expiresAt.toISOString(),
        merchant_type: "full",
      })
      .eq("id", user.id);

    // Refresh caches - use refetchQueries with timeout to prevent hanging
    const refetchWithTimeout = (queryKey: any[], ms = 5000) =>
      Promise.race([
        queryClient.refetchQueries({ queryKey }),
        new Promise((resolve) => setTimeout(resolve, ms)),
      ]);
    await refetchWithTimeout(["user-roles", user.id]);
    await refetchWithTimeout(["profile"]);
    
  };

  const checkStoresAndGuide = async () => {
    if (!user) return;
    const { data: stores } = await supabase
      .from("merchant_restaurants")
      .select("id")
      .eq("user_id", user.id);

    if (!stores || stores.length === 0) {
      setShowNoStoreDialog(true);
    }
  };

  const handlePurchaseResult = useCallback(async (msg: string, transactionId?: string) => {
    setPurchasing(false);
    const msgStr = String(msg);
    let status = "failed";
    if (msgStr === "success") status = "success";
    else if (msgStr === "userCancelled") status = "cancelled";
    else if (msgStr === "pending") status = "pending";

    const tier = TIERS.find(t => t.id === selectedTier)!;
    try {
      await createOrder.mutateAsync({
        product_id: tier.productId,
        status,
        apple_transaction_id: transactionId || undefined,
        amount: tier.price,
        currency: "USD",
        platform: "ios",
        error_message: status === "failed" ? msgStr : undefined,
      });

      if (status === "success" && user) {
        await assignRoleAfterPurchase(tier);
        await checkStoresAndGuide();
      }
    } catch (e) {
      console.error("Failed to save order:", e);
    }

    if (msgStr === "success") {
      toast({ title: t("membership.toast.success"), description: t("membership.toast.successDesc") });
    } else if (msgStr === "userCancelled") {
      toast({ title: t("membership.toast.cancelled"), description: t("membership.toast.cancelledDesc") });
    } else if (msgStr === "pending") {
      toast({ title: t("membership.toast.pending"), description: t("membership.toast.pendingDesc") });
    } else {
      toast({ title: t("membership.toast.failed"), description: `${t("membership.toast.error")}: ${msgStr}`, variant: "destructive" });
    }
  }, [toast, t, createOrder, selectedTier, user, queryClient]);

  // Handle restore result from native
  const handleRestoreResult = useCallback(async (msg: string, transactionId?: string) => {
    setRestoring(false);
    const msgStr = String(msg);

    if (msgStr === "success") {
      // Find the restored tier by product ID if provided, otherwise refresh profile
      if (transactionId) {
        // transactionId here could be the product ID of the restored subscription
        const restoredTier = TIERS.find(t => t.productId === transactionId);
        if (restoredTier && user) {
          try {
            await createOrder.mutateAsync({
              product_id: restoredTier.productId,
              status: "success",
              apple_transaction_id: transactionId,
              amount: restoredTier.price,
              currency: "USD",
              platform: "ios",
            });
            await assignRoleAfterPurchase(restoredTier);
          } catch (e) {
            console.error("Failed to save restored order:", e);
          }
        }
      }
      // Refresh profile & roles
      await queryClient.invalidateQueries({ queryKey: ["profile"] });
      await queryClient.invalidateQueries({ queryKey: ["user-roles"] });
      toast({ title: t("membership.toast.restoreSuccess", "恢复成功"), description: t("membership.toast.restoreSuccessDesc", "已成功恢复您的购买记录") });
    } else if (msgStr === "noPurchases") {
      toast({ title: t("membership.toast.restoreEmpty", "无可恢复的购买"), description: t("membership.toast.restoreEmptyDesc", "未找到之前的购买记录") });
    } else {
      toast({ title: t("membership.toast.restoreFailed", "恢复失败"), description: t("membership.toast.restoreFailedDesc", "恢复购买时出错，请稍后重试"), variant: "destructive" });
    }
  }, [toast, t, user, createOrder, queryClient]);

  useEffect(() => {
    (window as any).onReceivePurchase = (msg: any, transactionId?: any) => {
      handlePurchaseResult(String(msg), transactionId ? String(transactionId) : undefined);
    };
    (window as any).onRestoreResult = (msg: any, productId?: any) => {
      handleRestoreResult(String(msg), productId ? String(productId) : undefined);
    };
    return () => {
      delete (window as any).onReceivePurchase;
      delete (window as any).onRestoreResult;
    };
  }, [handlePurchaseResult, handleRestoreResult]);

  const executePurchase = (tierId: VipTier) => {
    setSelectedTier(tierId);
    setPurchasing(true);
    const tier = TIERS.find(t => t.id === tierId)!;
    try {
      const webkit = (window as any).webkit;
      if (webkit?.messageHandlers?.VoiceBridge) {
        webkit.messageHandlers.VoiceBridge.postMessage(`purchase:${tier.productId}`);
      } else {
        setPurchasing(false);
        toast({ title: t("membership.toast.notice"), description: t("membership.toast.purchaseInApp"), variant: "destructive" });
      }
    } catch {
      setPurchasing(false);
      toast({ title: t("membership.toast.error"), description: t("membership.toast.connectionError"), variant: "destructive" });
    }
  };

  const handlePurchase = (tierId: VipTier) => {
    if (!user) {
      toast({ title: t("membership.toast.loginRequired"), description: t("membership.toast.loginRequiredDesc"), variant: "destructive" });
      return;
    }

    // If user is not already a merchant/supervisor, show confirmation dialog
    if (!isAlreadyMerchant) {
      setPendingTierId(tierId);
      setShowConfirmDialog(true);
      return;
    }

    executePurchase(tierId);
  };

  const handleConfirmPurchase = () => {
    setShowConfirmDialog(false);
    if (pendingTierId) {
      executePurchase(pendingTierId);
      setPendingTierId(null);
    }
  };

  return (
    <div className="min-h-screen bg-background pb-24">
      <div className="px-4 pt-8 pb-6 max-w-lg mx-auto space-y-6">
        {/* Hero */}
        <div className="text-center space-y-3">
          <div className="inline-flex items-center justify-center h-14 w-14 rounded-2xl bg-gradient-to-br from-primary/20 to-primary/5 border border-primary/20">
            <Crown className="h-7 w-7 text-primary" />
          </div>
          <h1 className="text-2xl font-bold">{t("membership.title", "账号升级")}</h1>
          <p className="text-sm text-muted-foreground leading-relaxed">
            {t("membership.subtitle", "升级为商家身份，解锁完整商店管理功能")}
          </p>
        </div>

        {/* Current VIP status */}
        {isActive && currentVip && (
          <div className={cn(
            "rounded-xl border p-4 flex items-center gap-3",
            TIERS.find(t => t.id === currentVip)?.bgClass,
            TIERS.find(t => t.id === currentVip)?.borderClass,
          )}>
            <Crown className={cn("h-5 w-5", TIERS.find(t => t.id === currentVip)?.colorClass)} />
            <div className="flex-1">
              <p className="text-sm font-semibold">{t("membership.currentPlan", "当前套餐")}: {tierLabels[currentVip]}</p>
              <p className="text-xs text-muted-foreground">
                {t("membership.expiresAt", "到期时间")}: {new Date(vipExpiresAt!).toLocaleDateString()}
              </p>
            </div>
          </div>
        )}

        {/* Tier cards */}
        <div className="space-y-3">
          {TIERS.map((tier) => {
            const TierIcon = tier.icon;
            const isCurrent = isActive && currentVip === tier.id;
            return (
              <div
                key={tier.id}
                className={cn(
                  "rounded-xl border-2 p-5 transition-all relative",
                  isCurrent ? `${tier.borderClass} ${tier.bgClass}` : "border-border hover:border-primary/30",
                )}
              >
                {tier.id === "vip2" && (
                  <Badge className="absolute -top-2.5 right-4 bg-primary text-primary-foreground text-[10px] px-2">
                    {t("membership.popular", "最受欢迎")}
                  </Badge>
                )}

                <div className="flex items-start gap-4">
                  <div className={cn(
                    "h-11 w-11 rounded-xl flex items-center justify-center shrink-0",
                    tier.bgClass,
                  )}>
                    <TierIcon className={cn("h-5 w-5", tier.colorClass)} />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-semibold text-base">{tierLabels[tier.id]}</h3>
                      <Badge variant="outline" className={cn("text-[10px]", tier.badgeClass)}>
                        {tier.id.toUpperCase()}
                      </Badge>
                    </div>
                    
                    <div className="flex items-center gap-1 mb-3">
                      <Store className="h-3.5 w-3.5 text-muted-foreground" />
                      <span className="text-xs text-muted-foreground">
                        {t("membership.storeQuota", "可管理 {{count}} 个完整商店", { count: tier.storeCount })}
                      </span>
                    </div>

                    <div className="flex items-end justify-between">
                      <div>
                        <span className="text-2xl font-extrabold">
                          {productPrices[tier.productId]?.displayPrice ?? `$${tier.price}`}
                        </span>
                        <span className="text-xs text-muted-foreground ml-1">/{t("membership.perMonth", "月")}</span>
                      </div>
                      <Button
                        size="sm"
                        onClick={() => handlePurchase(tier.id)}
                        disabled={purchasing || isCurrent}
                        className="h-8 px-4 text-xs"
                        variant={isCurrent ? "outline" : "default"}
                      >
                        {purchasing && selectedTier === tier.id ? (
                          <Loader2 className="h-3 w-3 animate-spin" />
                        ) : isCurrent ? (
                          t("membership.currentPlan", "当前套餐")
                        ) : currentVip && isActive ? (
                          t("membership.upgrade", "升级")
                        ) : (
                          t("membership.subscribe", "立即订阅")
                        )}
                      </Button>
                    </div>
                  </div>
                </div>

                {/* Features list */}
                <div className="mt-3 pt-3 border-t border-border/50 space-y-1.5">
                  <div className="flex items-center gap-2">
                    <Check className="h-3.5 w-3.5 text-primary shrink-0" />
                    <span className="text-xs">{t("membership.feature.delivery", "外卖链接编辑与显示")}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Check className="h-3.5 w-3.5 text-primary shrink-0" />
                    <span className="text-xs">{t("membership.feature.booking", "订台链接编辑与显示")}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Check className="h-3.5 w-3.5 text-primary shrink-0" />
                    <span className="text-xs">{t("membership.feature.website", "官网链接编辑与显示")}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Check className="h-3.5 w-3.5 text-primary shrink-0" />
                    <span className="text-xs">{t("membership.feature.storeManagement", "商店管理与数据分析")}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Check className="h-3.5 w-3.5 text-primary shrink-0" />
                    <span className="text-xs">
                      {tier.storeCount === 1
                        ? t("membership.feature.oneStore", "管理 1 个完整商店")
                        : t("membership.feature.multiStore", "管理最多 {{count}} 个完整商店", { count: tier.storeCount })}
                    </span>
                  </div>
                  {tier.id !== "vip1" && (
                    <div className="flex items-center gap-2">
                      <Check className="h-3.5 w-3.5 text-primary shrink-0" />
                      <span className="text-xs">{t("membership.feature.prioritySupport", "优先客服支持")}</span>
                    </div>
                  )}
                  {tier.id === "vip3" && (
                    <div className="flex items-center gap-2">
                      <Check className="h-3.5 w-3.5 text-primary shrink-0" />
                      <span className="text-xs">{t("membership.feature.exclusiveBadge", "专属超级商家徽章")}</span>
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>

        {/* What is Account Upgrade */}
        <div className="rounded-xl border bg-card p-5 space-y-3">
          <div className="flex items-center gap-2">
            <Zap className="h-5 w-5 text-primary" />
            <h2 className="font-semibold text-base">{t("membership.whatIsTrafficPool", "什么是完整商店？")}</h2>
          </div>
          <p className="text-sm text-muted-foreground leading-relaxed">
            {t("membership.trafficPoolDesc", "完整商店拥有外卖链接、订台链接和官网链接的编辑权限，可自主管理这三个按钮的显示开关，实现自动化运营，提升曝光和订单量。")}
          </p>
        </div>

        {/* Restore Purchases */}
        <div className="text-center">
          <Button
            variant="outline"
            size="sm"
            className="text-xs"
            disabled={purchasing || restoring}
            onClick={() => {
              try {
                const webkit = (window as any).webkit;
                if (webkit?.messageHandlers?.VoiceBridge) {
                  setRestoring(true);
                  webkit.messageHandlers.VoiceBridge.postMessage("restore");
                  setTimeout(() => setRestoring(false), 30000);
                } else {
                  toast({ title: t("membership.toast.notice"), description: t("membership.toast.purchaseInApp"), variant: "destructive" });
                }
              } catch {
                toast({ title: t("membership.toast.error"), description: t("membership.toast.connectionError"), variant: "destructive" });
              }
            }}
          >
            {restoring ? (
              <Loader2 className="h-3.5 w-3.5 mr-1.5 animate-spin" />
            ) : (
              <RotateCcw className="h-3.5 w-3.5 mr-1.5" />
            )}
            {restoring
              ? t("membership.restoringPurchases", "Restoring...")
              : t("membership.restorePurchases", "Restore Purchases")}
          </Button>
        </div>

        {/* Footer */}
        <div className="text-center space-y-1 text-[11px] text-muted-foreground">
          <p>{t("membership.autoRenewNote", "Auto-renewing subscription, cancel anytime")}</p>
          <p>
            {t("membership.agreeToTerms", "By subscribing, you agree to our")}{" "}
            <a href="https://www.apple.com/legal/internet-services/itunes/dev/stdeula/" target="_blank" rel="noopener noreferrer" className="underline text-primary">{t("membership.termsOfUse", "Terms of Use")}</a>
            {" & "}
            <a href="/privacy-policy" className="underline text-primary">{t("membership.privacyPolicy", "Privacy Policy")}</a>
          </p>
        </div>
      </div>

      {/* Confirmation Dialog for non-merchants */}
      <AlertDialog open={showConfirmDialog} onOpenChange={setShowConfirmDialog}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle className="flex items-center gap-2">
              <AlertTriangle className="h-5 w-5 text-amber-500" />
              {t("membership.merchantWarningTitle", "商家身份升级确认")}
            </AlertDialogTitle>
            <AlertDialogDescription>
              {t("membership.merchantWarningDesc", "此为商家升级服务。购买后，您的账号将升级为商家身份，获得商家后台管理权限。确认继续？")}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t("common.cancel", "取消")}</AlertDialogCancel>
            <AlertDialogAction onClick={handleConfirmPurchase}>
              {t("membership.confirmUpgrade", "确认升级")}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* No Store Dialog - guide to merchant dashboard */}
      <Dialog open={showNoStoreDialog} onOpenChange={setShowNoStoreDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Store className="h-5 w-5 text-primary" />
              {t("membership.noStoreTitle", "升级成功！")}
            </DialogTitle>
            <DialogDescription>
              {t("membership.noStoreDesc", "您还没有商店，前往商家后台创建您的第一家商店吧！")}
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button
              onClick={() => {
                setShowNoStoreDialog(false);
                navigate("/merchant-dashboard");
              }}
              className="w-full"
            >
              {t("membership.goToDashboard", "前往商家后台")}
              <ArrowRight className="h-4 w-4 ml-1" />
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default Membership;
